// Parse Grafana Alerting webhook payload
// Extracts alert fields for Sentry event transformation
const body = $input.first().json.body || $input.first().json;
const alerts = body.alerts || [body];
const results = [];

for (const alert of alerts) {
  const status = alert.status || body.status || 'firing';
  if (status !== 'firing') continue;

  const labels = alert.labels || {};
  const annotations = alert.annotations || {};
  const values = alert.values || alert.valueString || '';

  const alertname = labels.alertname || body.title || body.commonLabels?.alertname || '';
  if (!alertname || alertname === 'Unknown Alert') continue;

  results.push({
    json: {
      alertname: alertname,
      severity: labels.severity || 'warning',
      status: status,
      summary: annotations.summary || annotations.description || '',
      values: typeof values === 'object' ? JSON.stringify(values) : String(values),
      dashboardURL: alert.dashboardURL || '',
      panelURL: alert.panelURL || '',
      startsAt: alert.startsAt || new Date().toISOString(),
      group: labels.grafana_folder || 'default'
    }
  });
}

return results.length > 0 ? results : [];

// Rate limiter - max 10 events per 5-minute window
const MAX_EVENTS = 10;
const WINDOW_MS = 5 * 60 * 1000;

const now = Date.now();
const staticData = $getWorkflowStaticData('global');

if (!staticData.glitchtipRateLimitEntries) {
  staticData.glitchtipRateLimitEntries = [];
}
staticData.glitchtipRateLimitEntries = staticData.glitchtipRateLimitEntries.filter(ts => now - ts < WINDOW_MS);

const isRateLimited = staticData.glitchtipRateLimitEntries.length >= MAX_EVENTS;

if (!isRateLimited) {
  staticData.glitchtipRateLimitEntries.push(now);
}

return [{
  json: {
    ...$input.first().json,
    isRateLimited,
    rateLimitCount: staticData.glitchtipRateLimitEntries.length,
    rateLimitMax: MAX_EVENTS
  }
}];

// Transform Grafana alert to Sentry event format for GlitchTip
// DSN format: http://<key>@<host>:<port>/<project_id>
const dsn = $env.GLITCHTIP_SENTRY_DSN || '';
if (!dsn) {
  throw new Error('GLITCHTIP_SENTRY_DSN environment variable not set');
}

// Parse DSN
const dsnMatch = dsn.match(/^https?:\/\/([^@]+)@([^/]+)\/(\d+)$/);
if (!dsnMatch) {
  throw new Error('Invalid GLITCHTIP_SENTRY_DSN format. Expected: http://<key>@<host>/<project_id>');
}
const [, sentryKey, sentryHost, projectId] = dsnMatch;

const SEVERITY_MAP = {
  'critical': 'fatal',
  'error': 'error',
  'warning': 'warning',
  'warn': 'warning',
  'info': 'info',
  'debug': 'debug'
};

const d = $input.first().json;
const eventId = crypto.randomUUID().replace(/-/g, '');

const sentryEvent = {
  event_id: eventId,
  timestamp: d.startsAt || new Date().toISOString(),
  level: SEVERITY_MAP[d.severity.toLowerCase()] || 'warning',
  logger: 'grafana.alerting',
  platform: 'other',
  server_name: 'grafana-104',
  environment: 'production',
  message: {
    formatted: `[${d.severity.toUpperCase()}] ${d.alertname}: ${d.summary || 'Alert triggered'}`,
    message: d.alertname
  },
  tags: {
    alertname: d.alertname,
    severity: d.severity,
    source: 'grafana',
    group: d.group || 'default'
  },
  extra: {
    values: d.values || '',
    dashboardURL: d.dashboardURL || '',
    panelURL: d.panelURL || ''
  },
  fingerprint: [d.alertname]
};

const storeUrl = `http://${sentryHost}/api/${projectId}/store/`;
const authHeader = `Sentry sentry_key=${sentryKey}, sentry_version=7, sentry_client=n8n-grafana-bridge/1.0`;

return [{
  json: {
    sentryEvent,
    storeUrl,
    authHeader,
    alertname: d.alertname,
    severity: d.severity
  }
}];
